customHandlers.d_h2w0gy:
function(ctx) {
  var categoryId = ctx.vodId;
  // 1. 获取该分类下的视频列表
  var videoListUrl = "https://api.cntv.cn/NewVideo/getVideoListByColumn?id={categoryId}&p=1&n=50&mode=0&serviceId=tvcctv".replace("{categoryId}", categoryId);
  var videoResp = req(videoListUrl);
  var videoJson = JSON.parse(videoResp.content);
  // 自动查找视频数组
  var videoArr = (function findArr(obj) {
    if (Array.isArray(obj)) return obj;
    for (var k in obj) {
      if (obj[k] && typeof obj[k] === 'object') {
        var res = findArr(obj[k]);
        if (res) return res;
      }
    }
    return null;
  })(videoJson);
  videoArr = videoArr || [];

  var resultVods = [];
  for (var i = 0; i < videoArr.length; i++) {
    var video = videoArr[i];
    var videoId = video["guid"] || "";
    var videoName = video["title"] || "无标题";
    var videoPic = video["pic"] || "";

    // 2. 获取该视频的剧集列表（如果有）
    var playList = [];
    if (true) {
      var episodeUrl = "https://api.cntv.cn/video/videoinfoByGuid?guid={videoId}&serviceId=tvcctv".replace("{videoId}", videoId);
      var epResp = req(episodeUrl);
      var epJson = JSON.parse(epResp.content);
      var episodes = epJson;
      var epPath = "data.list";
      if (epPath) {
        var parts = epPath.split(".");
        for (var j = 0; j < parts.length; j++) {
          if (episodes && episodes[parts[j]]) episodes = episodes[parts[j]];
          else episodes = null;
        }
      }
      if (episodes && Array.isArray(episodes)) {
        for (var k = 0; k < episodes.length; k++) {
          var ep = episodes[k];
          var epTitle = ep["title"] || "第" + (k+1) + "集";
          var epId = ep["guid"] || "";
          if (epId) playList.push(epTitle + "$" + epId);
        }
      }
    }
    // 如果没有分集，则将视频本身作为单集
    if (playList.length === 0 && videoId) {
      playList.push("全集$" + videoId);
    }
    var vod = {
      vod_id: videoId,
      vod_name: videoName,
      vod_pic: videoPic,
      vod_play_url: playList.join("#")
    };
    resultVods.push(vod);
  }
  return { list: resultVods };
}

customHandlers.p_dizwbw:
function(ctx) {
  var episodeId = ctx.id;
  var url = "https://vdn.apps.cntv.cn/api/getHttpVideoInfo.do?pid={episodeId}".replace("{episodeId}", episodeId);
  var resp = req(url);
  var json = JSON.parse(resp.content);
  var videoUrl = json["hls_url"] || json.url || json.video || "";
  return { parse: 0, playUrl: "", url: videoUrl };
}

customHandlers.h_s0bzkx:
function(ctx) {
  var resp = req("https://api.cntv.cn/lanmu/columnSearch?p=1&n=20&serviceId=tvcctv&t=json");
  var json = JSON.parse(resp.content);
  // 自动查找数组
  var arrayInfo = (function findArr(obj) {
    if (Array.isArray(obj)) return obj;
    for (var k in obj) {
      if (obj[k] && typeof obj[k] === 'object') {
        var res = findArr(obj[k]);
        if (res) return res;
      }
    }
    return null;
  })(json);
  var data = arrayInfo || [];
  var result = [];
  for (var i = 0; i < data.length; i++) {
    var item = data[i];
    var vod = {
      vod_id: item["id"] || "",
      vod_name: item["title"] || "未命名分类",
      vod_pic: item["pic"] || ""
    };
    result.push(vod);
  }
  return result;
}
